// 读取已提取的 JSON 数据
const inputData = $input.first().json;
let logData;

// 处理提取的数据
if (inputData.data) {
  try {
    logData = typeof inputData.data === 'string' ? JSON.parse(inputData.data) : inputData.data;
  } catch (e) {
    logData = inputData;
  }
} else {
  logData = inputData;
}

// 递归收集所有字段路径
function collectFields(obj, prefix = '', fields = [], maxDepth = 5, currentDepth = 0) {
  if (currentDepth >= maxDepth) return fields;

  for (const key in obj) {
    if (obj.hasOwnProperty(key)) {
      const fullPath = prefix ? `${prefix}.${key}` : key;
      const value = obj[key];

      if (value === null || value === undefined) {
        fields.push({ path: fullPath, type: 'null', sample: null });
      } else if (Array.isArray(value)) {
        fields.push({ path: fullPath, type: 'array', length: value.length });
        if (value.length > 0 && typeof value[0] === 'object' && value[0] !== null && currentDepth < maxDepth - 1) {
          collectFields(value[0], `${fullPath}[0]`, fields, maxDepth, currentDepth + 1);
        }
      } else if (typeof value === 'object') {
        fields.push({ path: fullPath, type: 'object', keys: Object.keys(value).slice(0, 5) });
        collectFields(value, fullPath, fields, maxDepth, currentDepth + 1);
      } else {
        const sample = typeof value === 'string' && value.length > 50 ? value.substring(0, 50) + '...' : value;
        fields.push({ path: fullPath, type: typeof value, sample: sample });
      }
    }
  }
  return fields;
}

// 收集所有字段
const allFields = collectFields(logData);

// 标记需要清洗的字段（根据之前的分析）
const fieldsToClean = [
  'Readable date',
  'Readable time',
  'Day of week',
  'Year',
  'Month',
  'Day of month',
  'Hour',
  'Minute',
  'Second'
];

// 生成字段清单
const fieldList = allFields.map(field => {
  const fieldName = field.path.split('.').pop() || field.path;
  const shouldClean = fieldsToClean.some(cleanField => fieldName === cleanField || field.path.includes(cleanField));
  return {
    path: field.path,
    type: field.type,
    should_clean: shouldClean,
    sample: field.sample,
    recommendation: shouldClean ? '清洗' : '保留'
  };
});

// 保存解析后的数据
return [{
  json: {
    execution_id: logData.data?.id || '',
    total_fields: allFields.length,
    fields_to_clean: fieldList.filter(f => f.should_clean).length,
    field_list: fieldList.slice(0, 200), // 限制输出数量
    original_data: logData, // 保留原始数据用于后续清洗
    parsed_data: logData // 便于后续节点使用
  }
}];

// 准备主执行记录数据
const cleaned = $input.first().json;
const data = cleaned.data || {};
const meta = cleaned._cleaned_meta || {};

// 计算执行时长
let durationMs = null;
if (data.startedAt && data.stoppedAt) {
  durationMs = new Date(data.stoppedAt) - new Date(data.startedAt);
}

// 保存 execution_logs 的 created_at，供子表使用（时间戳一致性优化）
const executionLogCreatedAt = data.createdAt || new Date().toISOString();

return [{
  json: {
    execution_log: {
      execution_id: data.id,
      workflow_id: data.workflowId,
      status: data.status,
      is_success: cleaned.isSuccess || false,
      created_at: executionLogCreatedAt,
      started_at: data.startedAt,
      stopped_at: data.stoppedAt,
      finished: data.finished || false,
      execution_duration_ms: durationMs,
      original_size: meta.original_size,
      cleaned_size: meta.cleaned_size,
      reduction_percent: meta.reduction_percent
    },
    cleaned_data: cleaned,
    execution_log_created_at: executionLogCreatedAt // 供子表使用
  }
}];

try {
  const prepareDataOutput = $('Step10_PrepareDatabaseData').first().json;
  const cleaned = prepareDataOutput.cleaned_data || {};
  const data = cleaned.data || {};

  // --- 1. 基础字段提取 (保留原逻辑) ---
  const baseData = {
    workflowId: data.workflowId || '',
    status: data.status || 'unknown',
    createdAt: data.createdAt || new Date().toISOString(),
    startedAt: data.startedAt || null,
    stoppedAt: data.stoppedAt || null
  };

  const allMarkets = [];
  const allAllocationData = [];
  let vaultName = '';
  let rebalanceDecision = null;

  const subExecutions = cleaned.data?.subExecutionLogs || [];

  subExecutions.forEach((subExec) => {
    const currentInfo = subExec.data?.resultData?.runData?.['Current Info']?.[0]?.data?.main?.[0]?.[0]?.json;
    const summary = subExec.data?.resultData?.runData?.Summary?.[0]?.data?.main?.[0]?.[0]?.json;
    const rebalanceCheck = subExec.data?.resultData?.runData?.['Rebalance Check']?.[0]?.data?.main?.[0]?.[0]?.json;

    if (!vaultName && summary?.name) { vaultName = summary.name; }

    if (!rebalanceDecision && rebalanceCheck) {
      // ✅ v4 新增字段提取: is_blocked 和 threshold_details
      // 资产来源: 07_Code-null值默认值处理-v1.0
      // 参考: Alex-Mike_19_Morpho_Execution_Log_RPC_v4_Database_Request_2025-01-30.md

      // 提取 is_blocked: 支持两种工作流结构（native 和 morpho）
      const isBlocked = rebalanceCheck?.conditions?.waitingPeriodBlocked || 
                       (rebalanceCheck?.reason && rebalanceCheck.reason.toLowerCase().includes('waiting period')) ||
                       false;

      // 提取 threshold_details: 构建 JSONB 结构
      const thresholdDetails = {
        thresholdsMet: rebalanceCheck?.conditions?.thresholdsMet || [],
        waitingPeriod: rebalanceCheck?.conditions?.waitingPeriod || null
      };

      rebalanceDecision = {
        rebalanceNeeded: rebalanceCheck.rebalanceNeeded || false,
        rebalanceReason: rebalanceCheck.reason || 'No rebalancing needed',
        is_blocked: isBlocked,  // ✅ v4 新增
        threshold_details: thresholdDetails  // ✅ v4 新增
      };
    }

    if (currentInfo?.allocationAndMarket) {
      const chainName = currentInfo.chainName || '';
      const marketData = currentInfo.allocationAndMarket[0]?.marketData || [];
      const allocationData = currentInfo.allocationAndMarket[0]?.allocationData || [];
      const strategies = currentInfo.strategies || [];
      const gasCost = strategies[0]?.workflowParams?.gasCost || null;

      marketData.forEach(market => {
        allMarkets.push({
          chain: market.chain || chainName,
          protocolName: market.protocolName || '',
          market: market.market || '',
          cap: market.cap || null,
          tvl: market.totalSupplied || null,
          baseApy: market.supplyApy || null,
          netApy: market.supplyApy || null,
          rewardApy: null,
          estDepositGas: gasCost || null
        });
      });

      allocationData.forEach(alloc => {
        allAllocationData.push({
          chain: alloc.chain || chainName,
          protocolName: alloc.protocolName || '',
          market: alloc.market || '',
          asset: alloc.asset || '',
          totalAllocated: alloc.totalAllocated || 0,
          idleLiquidity: alloc.idleLiquidity || 0,
          pendingWithdrawal: alloc.pendingWithdrawal || 0
        });
      });
    }
  });

  // --- 2. 嵌入波动守卫判定逻辑 (核心微调部分) ---
  const APY_THRESHOLD = 0.3;     
  const TVL_THRESHOLD = 0.05;    
  const HEARTBEAT_LIMIT = 12 * 60 * 60 * 1000; 

  let is_critical_event = false;
  let reason = "Normal state";

  // 获取参考数据 (假设你已有 Get_Last_Stat 节点，若无则默认为 true 确保安全入库)
  let lastExecution = null;
  try { lastExecution = $node["Get_Last_Stat"]?.json; } catch (e) { lastExecution = null; }

  if (rebalanceDecision?.rebalanceNeeded === true) {
    is_critical_event = true;
    reason = "Rebalance triggered";
  } else if (!lastExecution) {
    is_critical_event = true;
    reason = "Initial run or no history";
  } else if (allMarkets.length > 0) {
    const m = allMarkets[0];
    const lastApy = lastExecution.base_apy || 0;
    const lastTvl = lastExecution.tvl || 0;
    const lastTime = new Date(lastExecution.created_at).getTime();

    const apyDiff = Math.abs(m.baseApy - lastApy);
    const tvlChange = lastTvl > 0 ? Math.abs(m.tvl - lastTvl) / lastTvl : 1;

    if (apyDiff >= APY_THRESHOLD) {
      is_critical_event = true;
      reason = `APY Volatility: ${apyDiff.toFixed(2)}%`;
    } else if (tvlChange >= TVL_THRESHOLD) {
      is_critical_event = true;
      reason = `TVL Volatility: ${(tvlChange * 100).toFixed(2)}%`;
    } else if (Date.now() - lastTime > HEARTBEAT_LIMIT) {
      is_critical_event = true;
      reason = "12-hour Heartbeat";
    }
  }

  // --- 3. 构建最终输出 (完全兼容原 RPC 格式，仅增加判定位) ---
  const finalPayload = {
    ...baseData,
    vaultName: vaultName,
    markets: allMarkets,
    allocationData: allAllocationData,
    rebalanceDecision: rebalanceDecision || {
      rebalanceNeeded: false,
      rebalanceReason: 'No rebalancing data available',
      is_blocked: false,  // ✅ v4 新增：默认值
      threshold_details: null  // ✅ v4 新增：默认值
    },
    is_critical_event: is_critical_event,
    debug_reason: reason
  };

  return [{
    json: {
      json_data: finalPayload,
      cleaned_data: cleaned,
      execution_log_created_at: prepareDataOutput.execution_log_created_at
    }
  }];

} catch (error) {
  return [{ json: { error: true, error_message: error.message, success: false } }];
}

// Step13: 提取 ingestion 结果并传递 cleaned_data
const httpResponse = $node["Step12_CallRPCProcessLogData"].json;
const responseBody = httpResponse.body || httpResponse;
const originalData = $node["Step11_PrepareRPCJSONData"].json;

const ingestionStatus = responseBody.status || 'unknown';
const executionId = ingestionStatus === 'written' ? (responseBody.execution_id || '').toString().trim() : '';
const is_critical_event = ingestionStatus === 'written'
  ? (originalData.json_data?.is_critical_event || false)
  : false;

return {
  execution_id: executionId,
  ingestion_status: ingestionStatus,
  quarantine_reasons: responseBody.reasons || [],
  is_critical_event: is_critical_event,
  cleaned_data: originalData.cleaned_data,
  json_data: originalData.json_data
};

// 读取分析结果和原始数据
const inputData = $input.first().json;
const originalData = inputData.original_data || inputData.parsed_data;

if (!originalData) {
  throw new Error('原始数据不存在');
}

// 清洗函数：精简 Schedule Trigger 节点
function cleanScheduleTrigger(nodeData) {
  if (!nodeData || !nodeData.data || !nodeData.data.main) return nodeData;

  const cleaned = JSON.parse(JSON.stringify(nodeData));
  if (cleaned.data.main && cleaned.data.main[0] && cleaned.data.main[0][0]) {
    const json = cleaned.data.main[0][0].json;
    // 只保留 timestamp 和 Timezone
    cleaned.data.main[0][0].json = {
      timestamp: json.timestamp,
      Timezone: json.Timezone
    };
  }
  return cleaned;
}

// 清洗函数：精简节点执行数据
function cleanNodeExecution(nodeData) {
  if (!nodeData) return nodeData;

  const cleaned = {
    executionTime: nodeData.executionTime,
    executionStatus: nodeData.executionStatus,
    data: nodeData.data
  };

  // 清洗 data.main 中的 pairedItem
  if (cleaned.data && cleaned.data.main) {
    cleaned.data.main = cleaned.data.main.map(mainArray => 
      mainArray.map(item => ({ json: item.json }))
    );
  }

  return cleaned;
}

// 清洗函数：精简子执行日志
function cleanSubExecution(subExec) {
  if (!subExec) return null;

  const cleaned = {
    id: subExec.id,
    workflowId: subExec.workflowId,
    status: subExec.status,
    createdAt: subExec.createdAt,
    startedAt: subExec.startedAt,
    stoppedAt: subExec.stoppedAt,
    parentExecution: subExec.parentExecution
  };

  // 只保留关键节点的业务数据
  if (subExec.data && subExec.data.resultData && subExec.data.resultData.runData) {
    cleaned.data = {
      resultData: {
        runData: {}
      }
    };

    // 只保留关键节点：Summary, Rebalance Check, Current Info
    const keyNodes = ['Summary', 'Rebalance Check', 'Current Info', 'lastRebalancerInfo'];

    Object.keys(subExec.data.resultData.runData).forEach(nodeName => {
      if (keyNodes.includes(nodeName)) {
        const nodeData = subExec.data.resultData.runData[nodeName];
        if (Array.isArray(nodeData)) {
          cleaned.data.resultData.runData[nodeName] = nodeData.map(cleanNodeExecution);
        }
      }
    });
  }

  return cleaned;
}

// 主清洗逻辑
const cleaned = {
  isSuccess: originalData.isSuccess,
  status: originalData.status,
  timestamp: originalData.timestamp,
  data: {
    id: originalData.data?.id,
    workflowId: originalData.data?.workflowId,
    status: originalData.data?.status,
    createdAt: originalData.data?.createdAt,
    startedAt: originalData.data?.startedAt,
    stoppedAt: originalData.data?.stoppedAt,
    finished: originalData.data?.finished,
    data: {
      resultData: {
        runData: {}
      }
    }
  }
};

// 清洗主工作流的节点数据
if (originalData.data?.data?.resultData?.runData) {
  const runData = originalData.data.data.resultData.runData;

  Object.keys(runData).forEach(nodeName => {
    if (nodeName === 'Schedule Trigger') {
      if (runData[nodeName] && runData[nodeName][0]) {
        cleaned.data.data.resultData.runData[nodeName] = [cleanScheduleTrigger(runData[nodeName][0])];
      }
    } else {
      if (Array.isArray(runData[nodeName])) {
        cleaned.data.data.resultData.runData[nodeName] = runData[nodeName].map(cleanNodeExecution);
      }
    }
  });
}

// 清洗子执行日志
if (originalData.data?.subExecutionLogs) {
  cleaned.data.subExecutionLogs = originalData.data.subExecutionLogs
    .map(cleanSubExecution)
    .filter(subExec => subExec !== null);
}

// 添加清洗元数据
const originalSize = JSON.stringify(originalData).length;
const cleanedSize = JSON.stringify(cleaned).length;

cleaned._cleaned_meta = {
  cleaned_at: new Date().toISOString(),
  original_size: originalSize,
  cleaned_size: cleanedSize,
  reduction_percent: ((1 - cleanedSize / originalSize) * 100).toFixed(2),
  fields_removed: inputData.fields_to_clean || 0
};

return [{
  json: cleaned
}];

/**
 * Build RAG Document: 生产级语义增强版
 * 1. 语义定性：将 APY 等数字转化为高/中/低描述，方便向量检索。
 * 2. 强上下文：在正文顶部加入检索锚点（TAG）。
 * 3. 结构拆分：每个 Vault 独立成文。
 * 4. 修正：使用 Step13 返回的 UUID 作为 execution_id（不是 n8n 原始数字 ID）
 * 5. ⚠️ 修复：确保 execution_id 始终是字符串格式（不是对象）
 * 6. ✅ v4 优化：Metadata 瘦身为 9 维标签（符合"SQL 存事实，RAG 存因果"哲学）
 * 资产来源: 07_Code-null值默认值处理-v1.0, 08_Code-错误处理基础-v1.0
 * 参考: Mike_DatabaseExpert/4.Working/Database/RAG_Metadata_字段映射表_2025-01-30.md
 */
// === Step14: Build RAG Document v4 优化版 ===

// ✅ 关键修正：从 Step13 获取 UUID（数据库 UUID，不是 n8n 原始数字 ID）
const step13Output = $('Step13_ExtractExecutionID').first().json;
let executionIdRaw = step13Output.execution_id || '';

// ⚠️ 修复：确保 execution_id 始终是字符串格式
let executionId = '';
if (typeof executionIdRaw === 'string') {
  executionId = executionIdRaw.trim();
} else if (executionIdRaw && typeof executionIdRaw === 'object') {
  // 如果是对象，尝试提取内部的 execution_id 字段
  executionId = (executionIdRaw.execution_id || executionIdRaw.id || '').toString().trim();
} else if (executionIdRaw) {
  // 其他类型，转换为字符串
  executionId = executionIdRaw.toString().trim();
}

// 从 Step10 获取其他数据
const prepareDataOutput = $('Step10_PrepareDatabaseData').first().json;
const cleaned = prepareDataOutput.cleaned_data || {};
const data = cleaned.data || {};

const workflowId = data.workflowId || '';
const status = data.status || '';
const createdAt = data.createdAt || '';

const subExecutions = cleaned.data?.subExecutionLogs || [];
let documents = [];

subExecutions.forEach((subExec, idx) => {
  const summary = subExec.data?.resultData?.runData?.Summary?.[0]?.data?.main?.[0]?.[0]?.json;
  const rebalanceCheck = subExec.data?.resultData?.runData?.['Rebalance Check']?.[0]?.data?.main?.[0]?.[0]?.json;
  const currentInfo = subExec.data?.resultData?.runData?.['Current Info']?.[0]?.data?.main?.[0]?.[0]?.json;

  if (summary || rebalanceCheck || currentInfo) {
    let narrative = [];
    const vault = summary?.name || 'Unknown Vault';
    const chain = currentInfo?.chainName || 'Unknown Chain';

    // --- 1. 业务指标定性分析 ---
    const marketData = currentInfo?.allocationAndMarket?.[0]?.marketData || [];
    const apys = marketData.map(m => m.supplyApy || 0);
    const maxApy = apys.length > 0 ? Math.max(...apys) : 0;

    // 定性描述 APY 水平 (语义锚点)
    let apyPerformance = "stable";
    if (maxApy > 8) apyPerformance = "high-yielding";
    else if (maxApy > 4) apyPerformance = "competitive";
    else if (maxApy > 0 && maxApy <= 2) apyPerformance = "low-yield";

    // ✅ 修复：Market Details 数据清洗（去除空值和重复逗号）
    const marketNames = marketData
      .map(m => m.market)
      .filter(Boolean) // 去除空值、null、undefined
      .filter((name, index, arr) => arr.indexOf(name) === index) // 去重
      .join(', '); // 用逗号和空格连接

    const totalAllocated = currentInfo?.allocationAndMarket?.[0]?.allocationData?.reduce((sum, a) => sum + (parseFloat(a.totalAllocated) || 0), 0) || 0;

    // --- 2. 构建叙述性正文 (page_content) ---
    // 顶部加入强特征标签，防止向量检索时的链间干扰
    narrative.push(`[LOG_ANCHOR: ${chain.toUpperCase()}_${vault.replace(/\s+/g, '_').toUpperCase()}]`);

    narrative.push(`On ${createdAt}, the autonomous agent performed a routine management task for the ${vault} on ${chain}.`);

    narrative.push(`The current market environment for this vault is characterized as ${apyPerformance}, with the highest available Supply APY reaching ${maxApy.toFixed(2)}%.`);

    if (rebalanceCheck) {
      const rebalanceStatus = rebalanceCheck.rebalanceNeeded ? "active rebalancing was triggered" : "no rebalancing was required";
      narrative.push(`Strategic Analysis: The system determined that ${rebalanceStatus}. The logic behind this decision was: ${rebalanceCheck.reason || 'all parameters are within safe thresholds'}.`);
    }

    if (marketData.length > 0) {
      narrative.push(`Market Details: The agent monitored ${marketData.length} specific markets, including ${marketNames || 'N/A'}.`);
    }

    narrative.push(`Financial Summary: The total capital currently allocated across the protocols is ${totalAllocated.toFixed(2)} USD. The overall execution status ended in ${status}.`);

    // --- 3. 构建 9 维 Metadata（v4 优化：瘦身为 9 维标签）---
    // 资产来源: 07_Code-null值默认值处理-v1.0
    // 参考: Mike_DatabaseExpert/4.Working/Database/RAG_Metadata_字段映射表_2025-01-30.md

    // ✅ 提取 asset 和 protocol_name（9 维标签新增字段）
    const asset = currentInfo?.allocationAndMarket?.[0]?.allocationData?.[0]?.asset || 
                  currentInfo?.allocationAndMarket?.[0]?.marketData?.[0]?.asset || 
                  'Unknown';
    const protocolName = currentInfo?.allocationAndMarket?.[0]?.allocationData?.[0]?.protocolName || 
                         currentInfo?.allocationAndMarket?.[0]?.marketData?.[0]?.protocolName || 
                         'Unknown';

    // ✅ 提取 is_blocked（支持两种工作流结构）
    const isBlocked = rebalanceCheck?.conditions?.waitingPeriodBlocked || 
                     (rebalanceCheck?.reason && rebalanceCheck.reason.toLowerCase().includes('waiting period')) ||
                     false;

    // ✅ 提取 rebalance_reason（用于因果追溯）
    const rebalanceReason = rebalanceCheck?.reason || '';

    // ✅ 9 维标签（符合"SQL 存事实，RAG 存因果"哲学）
    const enhancedMetadata = {
      execution_id: executionId, // 1. execution_id
      vault_name: vault, // 2. vault_name
      chain_name: chain, // 3. chain_name
      asset: asset, // 4. asset ✅ 新增
      protocol_name: protocolName, // 5. protocol_name ✅ 新增
      is_blocked: isBlocked, // 6. is_blocked ✅ 新增
      apy_level: apyPerformance, // 7. apy_level（语义标签，非数值）
      rebalance_reason: rebalanceReason, // 8. rebalance_reason ✅ 新增（用于因果追溯）
      created_at: createdAt // 9. created_at
      // ❌ 移除的字段: workflow_id, source_type, max_apy, involved_markets, total_allocated_sum, rebalance_needed, rebalance_success, status, snapshot_type
    };

    documents.push({
      json: {
        page_content: narrative.join('\n\n'),
        metadata: enhancedMetadata
      }
    });
  }
});

return documents;

// 获取上一个节点（Fetch Data）的输出
const data = $json;

// 1. 判断 isSuccess 是否为 true
if (!data.isSuccess || data.data?.payloadJsonObject.allocationAndMarket == undefined ) {
  // 中断 workflow，并抛出错误
  throw new Error(data.message || "Unknown error: request failed");
}

// 2. 如果 isSuccess 为 true，输出 allocationAndMarketData
return [
  {
    json: {
      allocationAndMarket: data.data?.payloadJsonObject.allocationAndMarket || null
    }
  }
];

// N8N Code Node Bundle: morpho-pre-rebalance-checker
// Generated on: 2025-12-22T06:27:39.280Z
// Ready to copy-paste into N8N Code Node - no modifications needed!

// This code doesn't require any external dependencies

// === morpho/morpho-pre-rebalance-checker.js ===
// Morpho Rebalance Checker - Checks Morpho vault allocation and APY against thresholds
// Handles Morpho's supply/withdraw queue system

/**
 * Compare Morpho backend data states to detect rebalancing needs
 * @param {Object} current - Current backend data structure
 * @param {Object} last - Last backend data structure
 * @returns {Object} Comparison analysis
 */
function compareMorphoStates(current, last, vaultConfig) {
  const analysis = {
    rebalanceNeeded: false,
    reasons: [],
    recommendations: [],
    apyChanges: [],
    allocationChanges: [],
  };

  if (!current) {
    throw new Error("Invalid current backend data");
  }

  // If no previous data, no comparison possible
  if (!last) {
    return {
      rebalanceNeeded: true,
      reasons: ["initial_rebalance"],
      recommendations: [],
      apyChanges: [],
      allocationChanges: [],
    };
  }

  const currentData = current;
  const lastData = last;

  // Get market data for APY comparisons
  const currentMarkets = currentData.marketData || [];
  const lastMarkets = lastData.marketData || [];

  // Get allocation data for allocation comparisons
  const currentAllocations = currentData.allocationData || [];
  const lastAllocations = lastData.allocationData || [];

  // Check if new markets have been added or removed
  // use allocation data as idle liquidity is not included in market data
  const newMarkets = currentAllocations.filter(
    (m) => !lastAllocations.some((lm) => lm.market === m.market)
  );

  const removedMarkets = lastAllocations.filter(
    (m) => !currentAllocations.some((cm) => cm.market === m.market)
  );

  if (newMarkets.length > 0 || removedMarkets.length > 0) {
    analysis.rebalanceNeeded = true;
    analysis.reasons.push("market_added_or_removed");
    analysis.recommendations.push(
      `${newMarkets.length} markets added and ${removedMarkets.length} markets removed`
    );

    return analysis;
  }

  // Calculate total allocations for percentage calculations
  const currentTotal = currentAllocations.reduce(
    (sum, a) => sum + (a.totalAllocated || 0) + (a.idleLiquidity || 0),
    0
  );
  const lastTotal = lastAllocations.reduce(
    (sum, a) => sum + (a.totalAllocated || 0) + (a.idleLiquidity || 0),
    0
  );

  // 1. Check APY absolute changes using market data
  currentMarkets.forEach((currentMarket) => {
    const lastMarket = lastMarkets.find(
      (m) =>
        m.market === currentMarket.market &&
        m.protocolName === currentMarket.protocolName
    );
    if (lastMarket) {
      const apyChange = Math.abs(
        (currentMarket.supplyApy || 0) - (lastMarket.supplyApy || 0)
      );

      if (apyChange > vaultConfig.workflowParams.rebalanceAPYAbsoluteChange) {
        analysis.rebalanceNeeded = true;
        analysis.reasons.push("apy_absolute_change");
        analysis.apyChanges.push({
          market: currentMarket.market,
          currentAPY: currentMarket.supplyApy || 0,
          lastAPY: lastMarket.supplyApy || 0,
          change: apyChange,
        });
        analysis.recommendations.push(
          `${currentMarket.market} APY changed by ${apyChange.toFixed(2)}% (${(
            lastMarket.supplyApy || 0
          ).toFixed(2)}% → ${(currentMarket.supplyApy || 0).toFixed(2)}%)`
        );
      }
    }
  });

  // 2. Check supply cap changes using market data
  currentMarkets.forEach((currentMarket) => {
    const lastMarket = lastMarkets.find(
      (m) =>
        m.market === currentMarket.market &&
        m.protocolName === currentMarket.protocolName
    );
    if (lastMarket) {
      const currentCap = currentMarket.cap || 0;
      const lastCap = lastMarket.cap || 0;

      if (currentCap !== lastCap) {
        analysis.rebalanceNeeded = true;
        analysis.reasons.push("supply_cap_change");
        analysis.recommendations.push(
          `${currentMarket.market} supply cap changed: ${lastCap.toLocaleString()} → ${currentCap.toLocaleString()}`
        );
        console.log(`📏 Supply cap change detected: ${currentMarket.market} (${lastCap.toLocaleString()} → ${currentCap.toLocaleString()})`);
      }
    }
  });

  // 3. Check allocation percentage changes using allocation data
  currentAllocations.forEach((currentAllocation) => {
    const lastAllocation = lastAllocations.find(
      (a) =>
        a.market === currentAllocation.market &&
        a.protocolName === currentAllocation.protocolName
    );
    if (lastAllocation && currentTotal > 0 && lastTotal > 0) {
      const currentAmount =
        (currentAllocation.totalAllocated || 0) +
        (currentAllocation.idleLiquidity || 0);
      const lastAmount =
        (lastAllocation.totalAllocated || 0) +
        (lastAllocation.idleLiquidity || 0);

      const currentPercentage = (currentAmount / currentTotal) * 100;
      const lastPercentage = (lastAmount / lastTotal) * 100;
      const percentageChange = Math.abs(currentPercentage - lastPercentage);

      if (
        percentageChange >
        vaultConfig.workflowParams.rebalanceAllocationPercentageChange
      ) {
        analysis.rebalanceNeeded = true;
        analysis.reasons.push("allocation_percentage_change");
        analysis.allocationChanges.push({
          market: currentAllocation.market,
          currentPercentage,
          lastPercentage,
          change: percentageChange,
        });
        analysis.recommendations.push(
          `${
            currentAllocation.market
          } allocation changed by ${percentageChange.toFixed(
            1
          )}% (${lastPercentage.toFixed(1)}% → ${currentPercentage.toFixed(
            1
          )}%)`
        );
      }
    }
  });

  return analysis;
}

/**
 * Check if Morpho vault needs rebalancing using backend data structure
 * @param {Object} current - Current backend data structure
 * @param {Object} last - Last backend data structure
 * @param {Object} vaultConfig - Vault configuration
 * @returns {Promise<Object>} Rebalance check result
 */
async function checkMorphoRebalance(current, last, vaultConfig) {
  console.log("🔍 Analyzing Morpho vault for rebalancing opportunities...");

  if (!current) {
    throw new Error("Invalid current backend data");
  }

  // Compare current vs last state for rebalancing opportunities
  const analysis = compareMorphoStates(current, last, vaultConfig);

  // Log basic info
  const currentData = current;
  const marketData = currentData.marketData || [];
  const allocations = currentData.allocationData || [];

  const totalValue = allocations.reduce(
    (sum, a) => sum + (a.totalAllocated || 0) + (a.idleLiquidity || 0),
    0
  );
  const apyValues = marketData.map((m) => m.supplyApy || 0);
  const minAPY = apyValues.length > 0 ? Math.min(...apyValues) : 0;
  const maxAPY = apyValues.length > 0 ? Math.max(...apyValues) : 0;

  console.log(
    `💰 Total value: ${totalValue.toFixed(2)} ${
      vaultConfig.asset?.symbol || "USDC"
    }`
  );
  console.log(
    `📊 Markets: ${marketData.length}, APY range: ${minAPY.toFixed(
      2
    )}% - ${maxAPY.toFixed(2)}%`
  );

  const vaultName = current.strategies?.[0]?.name || "Morpho Vault";
  console.log(
    `${analysis.rebalanceNeeded ? "✅" : "❌"} Rebalance ${
      analysis.rebalanceNeeded ? "NEEDED" : "not needed"
    } for ${vaultName}`
  );

  if (analysis.rebalanceNeeded) {
    console.log(`📋 Reasons: ${analysis.reasons.join(", ")}`);
    if (analysis.recommendations.length > 0) {
      console.log("💡 Recommendations:");
      analysis.recommendations.forEach((rec) => console.log(`  • ${rec}`));
    }
  }

  return {
    rebalanceNeeded: analysis.rebalanceNeeded,
    reason: analysis.reasons.join(", ") || "No rebalancing needed",
    reasons: analysis.reasons,
    recommendations: analysis.recommendations,
    analysis: analysis,
    vaultName: vaultName,
    timestamp: new Date().toISOString(),
  };
}

/**
 * Execute Morpho rebalance checker for N8N
 * @param {Object} input - N8N input with current/last Morpho data and vaultConfig
 * @returns {Promise<Object>} N8N response
 */
async function executeMorphoPreRebalanceCheckerForN8N(input) {
  const startTime = Date.now();

  try {
    const current = input.current || {};
    const last = input.last || null;
    const vaultConfig = input.vaultConfig || input.config || {};

    const result = await checkMorphoRebalance(current, last, vaultConfig);

    return {
      success: true,
      timestamp: new Date().toISOString(),
      executionTimeMs: Date.now() - startTime,

      // Main result
      rebalanceNeeded: result.rebalanceNeeded,
      reason: result.reason,
      vaultName: result.vaultName,

      // For N8N routing
      json: {
        rebalanceNeeded: result.rebalanceNeeded,
        reason: result.reason,
        analysis: result.analysis,
        vaultName: result.vaultName,
      },
    };
  } catch (error) {
    return {
      success: false,
      timestamp: new Date().toISOString(),
      executionTimeMs: Date.now() - startTime,
      error: error.message,
      json: {
        rebalanceNeeded: false,
        error: error.message,
      },
    };
  }
}

// Top-level execution for N8N (only when N8N globals are available)
let result;
if (typeof $input !== "undefined" && typeof $ !== "undefined") {
  const input = {
    config: $("Start").first().json.config,
    last: $input.first().json.allocationAndMarket[0],
    current: $("Current Info").first().json.allocationAndMarket[0],
  };

  result = executeMorphoPreRebalanceCheckerForN8N(input);
}


// N8N Execution - Ready to run!
return result;

