// N8N Code Node Bundle: morpho-parser
// Generated on: 2025-12-22T06:27:39.278Z
// Ready to copy-paste into N8N Code Node - no modifications needed!

// This code doesn't require any external dependencies

// === morpho/morpho-parser.js ===
// Morpho GraphQL Data Parser
// Converts Morpho vault allocation and market data to system format

/**
 * Field mapping configuration for Morpho GraphQL data to system format
 * Change these mappings to adjust field transformations without modifying core logic
 */
const MORPHO_FIELD_MAPPINGS = {
  // Merged data field mappings - combining both market and allocation data
  merged: {
    // Basic market info
    marketExposure: (market) =>
      market.collateralAsset
        ? `${market.collateralAsset.symbol}/${market.loanAsset.symbol}`
        : "Idle Liquidity",

    // Market size and liquidity data
    totalMarketSize: (market, allocation, vaultConfig) =>
      market.state.size / Math.pow(10, vaultConfig.asset.decimals),
    availableLiquidity: (market, allocation, vaultConfig) =>
      market.state.liquidityAssets / Math.pow(10, vaultConfig.asset.decimals),

    // Allocation amounts
    totalAllocated: (market, allocation, vaultConfig) =>
      parseFloat(allocation.supplyAssets) /
      Math.pow(10, vaultConfig.asset.decimals),

    // Financial data (convert decimals and percentages)
    utilizationRate: (market) => (market.state.utilization || 0) * 100,
    APY: (market) => (market.state.avgNetSupplyApy || 0) * 100,

    targetBorrowUtilization: (market) =>
      (parseFloat(market.targetBorrowUtilization) / 1e18) * 100,

    // Capacity and limits
    supplyCap: (market, allocation, vaultConfig) =>
      parseFloat(allocation.supplyCap) /
      Math.pow(10, vaultConfig.asset.decimals),

    // Morpho-specific fields
    uniqueKey: (market) => market.uniqueKey,

    id: (market) => market.id,
  },

  // Summary calculation mappings
  summary: {
    totalLiquidity: (markets) =>
      markets.reduce((sum, m) => sum + (m.liquidityAssets || 0), 0),
    totalSupplied: (allocations) =>
      allocations.reduce((sum, a) => sum + (a.totalAllocated || 0), 0),
    averageAPY: (allocations) => {
      const activeAllocs = allocations.filter((a) => a.totalAllocated > 0);
      if (activeAllocs.length === 0) return 0;
      return (
        activeAllocs.reduce((sum, a) => sum + (a.APY || 0), 0) /
        activeAllocs.length
      );
    },
    collateralTypes: (markets) => [
      ...new Set(
        markets.map((m) => m.marketExposure.split("/")[0]).filter(Boolean)
      ),
    ],
    highestUtilization: (markets) =>
      markets.length > 0
        ? Math.max(...markets.map((m) => m.utilizationRate))
        : 0,
    lowestUtilization: (markets) =>
      markets.length > 0
        ? Math.min(...markets.map((m) => m.utilizationRate))
        : 0,
  },
};

/**
 * Parse Morpho GraphQL response into allocation and market data
 * @param {Array} graphqlResponse - Array of GraphQL responses from Morpho
 * @param {Object} vaultConfig - Vault configuration with asset decimals
 * @returns {Object} Parsed data containing markets and allocation
 */
function parseMorphoData(graphqlResponse, vaultConfig) {
  // Validate decimals in config
  if (!vaultConfig?.asset?.decimals) {
    throw new Error(`Asset decimals not specified in vault config`);
  }

  if (!Array.isArray(graphqlResponse) || graphqlResponse.length === 0) {
    throw new Error("Invalid GraphQL response structure");
  }

  // Process the first response (assuming single vault query)
  const response = graphqlResponse[0];
  if (!response?.data?.vaultByAddress) {
    throw new Error("Invalid GraphQL response structure");
  }
  const results = {
    markets: [],
    allocation: [],
    totalValue: 0,
    vaultName: null,
  };

  const vault = response.data.vaultByAddress;
  results.vaultName = vault.name;

  const allocations = vault.state?.allocation || [];

  // Process each allocation item
  allocations.forEach((allocation) => {
    const market = allocation.market;

    // Create merged data entry using unified field mappings
    const mergedData = {};
    const mergedMappings = MORPHO_FIELD_MAPPINGS.merged;

    // Apply each field mapping
    for (const [fieldName, mappingFunction] of Object.entries(mergedMappings)) {
      mergedData[fieldName] = mappingFunction(market, allocation, vaultConfig);
    }

    // Filter out markets with both supply cap = 0 and total allocated = 0
    const hasSupplyCap = mergedData.supplyCap > 0;
    const hasAllocation = mergedData.totalAllocated > 0;

    if (hasSupplyCap || hasAllocation) {
      // Calculate total value using the mapped totalAllocated and idleLiquidity
      results.totalValue += mergedData.totalAllocated;
      results.markets.push(mergedData);
    } else {
      console.log(
        `🚫 Filtered out market: ${mergedData.marketExposure} (supplyCap: ${mergedData.supplyCap}, totalAllocated: ${mergedData.totalAllocated})`
      );
    }
  });

  return results;
}

/**
 * Execute Morpho parser for N8N - main entry point
 * @param {Object} input - Input containing morphoGraphQLData and config
 * @returns {Object} N8N-compatible response with parsed data
 */
function executeMorphoParserForN8N(input) {
  const startTime = Date.now();

  // Extract data from input
  const morphoGraphQLData = input.morphoGraphQLData || [];
  const config = input.config || null;

  // Parse the Morpho data
  const parsed = parseMorphoData(morphoGraphQLData, config);

  const executionTime = Date.now() - startTime;

  // Create N8N-compatible response
  const result = {
    success: true,
    timestamp: new Date().toISOString(),
    executionTimeMs: executionTime,

    // Parsed data
    vaultName: parsed.vaultName,
    totalValue: parsed.totalValue,

    // Markets data (compatible with existing markets module)
    markets: parsed.markets,

    // JSON output for N8N workflow routing
    json: {
      markets: parsed.markets,
      vaultName: parsed.vaultName,
      totalValue: parsed.totalValue,
    },
  };

  return result;
}

// Top-level execution for N8N (only when N8N globals are available)
let result;
if (typeof $input !== "undefined" && typeof $ !== "undefined") {
  const input = {
    morphoGraphQLData: $input.all().map((item) => item.json),
    config: $("Start").first().json.config,
  };
  result = executeMorphoParserForN8N(input);
}


// N8N Execution - Ready to run!
return result;

// N8N Code Node Bundle: morpho-to-backend-adapter
// Generated on: 2025-12-22T06:27:39.281Z
// Ready to copy-paste into N8N Code Node - no modifications needed!

// This code doesn't require any external dependencies

// === morpho/morpho-to-backend-adapter.js ===
// Morpho to Backend Database Structure Adapter
// Converts Morpho parser output to match existing backend database format

/**
 * Convert Morpho parsed data to backend database structure
 * @param {Object} morphoData - Parsed Morpho data
 * @param {Object} vaultConfig - Vault configuration
 * @param {Object} executionContext - N8N execution context
 * @returns {Array} Backend-compatible data structure
 */
function convertMorphoToBackendFormat(
  morphoData,
  vaultConfig,
  executionContext
) {
  if (!morphoData || !morphoData.markets) {
    throw new Error("Invalid Morpho data structure");
  }

  if (!vaultConfig || !vaultConfig.asset) {
    throw new Error("Invalid vault configuration");
  }

  // Extract execution context
  const workflowId = executionContext.workflowId || "unknown";
  const executionId = executionContext.executionId || "unknown";
  const ledgerAddress = vaultConfig.contractAddresses.vault;
  const chainName = vaultConfig.chain;

  // Get asset info from vault config
  const asset = vaultConfig.asset.symbol || "USDC";
  const decimals = vaultConfig.asset.decimals || 6;
  const chain = vaultConfig.chain || "mainnet";

  // Convert markets to allocationData format
  const allocationData = morphoData.markets.map((market) => {
    const isIdleLiquidity = market.marketExposure === "Idle Liquidity";

    return {
      chain: chain,
      protocolName: isIdleLiquidity ? "" : "Morpho",
      market: market.marketExposure,
      asset: asset,
      decimals: decimals,
      totalAllocated: isIdleLiquidity ? 0 : market.totalAllocated || 0,
      idleLiquidity: isIdleLiquidity ? market.totalAllocated || 0 : 0,
      pendingWithdrawal: 0, // Morpho doesn't have pending withdrawals in this context
    };
  });

  // Convert markets to backend market format
  const marketData = morphoData.markets
    .filter((market) => market.marketExposure !== "Idle Liquidity") // Exclude idle liquidity from market data
    .map((market) => ({
      chain: chain,
      protocolName: "Morpho",
      market: market.marketExposure,
      asset: asset,
      cap: market.supplyCap || 0,
      supplyApy: market.APY || 0,
      borrowApy: 0, // Morpho vault doesn't expose borrow APY in this context
      ur: market.utilizationRate || 0,
      totalSupplied: market.totalMarketSize || 0,
      totalBorrowed:
        ((market.totalMarketSize || 0) * (market.utilizationRate || 0)) / 100,
      liquidity: market.availableLiquidity || 0,
    }));

  // Build strategy object from vault config
  const strategy = vaultConfig;

  // Return in backend format
  return [
    {
      workflowId: workflowId,
      executionId: executionId,
      ledgerAddress: ledgerAddress,
      chainName: chainName,
      allocationAndMarket: [
        {
          allocationData: allocationData,
          marketData: marketData,
        },
      ],
      strategies: [strategy],
      triggerRebalancer: false, // Default to false, can be overridden
    },
  ];
}

/**
 * Execute Morpho to Backend adapter for N8N
 * @param {Object} input - N8N input data
 * @returns {Object} N8N response with backend-compatible data
 */
async function executeMorphoToBackendAdapterForN8N(input) {
  const startTime = Date.now();

  try {
    // Extract input data
    const morphoData = input.morphoData || {};
    const vaultConfig = input.vaultConfig || {};

    // Extract N8N execution context
    const executionContext = {
      workflowId: input.workflowId || process.env.WORKFLOW_ID || "unknown",
      executionId: input.executionId || process.env.EXECUTION_ID || "unknown",
    };

    console.log("🔄 Converting Morpho data to backend format...");
    console.log(`📊 Vault: ${morphoData.vaultName || "Unknown"}`);
    console.log(`🏪 Markets: ${morphoData.markets?.length || 0}`);

    // Convert to backend format
    const backendData = convertMorphoToBackendFormat(
      morphoData,
      vaultConfig,
      executionContext
    );

    console.log("✅ Successfully converted to backend format");
    console.log(
      `📋 Allocation entries: ${backendData[0].allocationAndMarket[0].allocationData.length}`
    );
    console.log(
      `📈 Market entries: ${backendData[0].allocationAndMarket[0].marketData.length}`
    );

    return {
      success: true,
      timestamp: new Date().toISOString(),
      executionTimeMs: Date.now() - startTime,

      // Main result - backend compatible format
      backendData: backendData,

      // For N8N routing
      json: backendData[0], // Return first (and only) element for easier access
    };
  } catch (error) {
    console.error("❌ Morpho to Backend conversion failed:", error.message);

    return {
      success: false,
      timestamp: new Date().toISOString(),
      executionTimeMs: Date.now() - startTime,
      error: error.message,
      json: {
        error: error.message,
        backendData: [],
      },
    };
  }
}

// Top-level execution for N8N (only when N8N globals are available)
let result;
if (typeof $input !== "undefined" && typeof $ !== "undefined") {
  const input = {
    morphoData: $input.first().json,
    vaultConfig: $("Start").first().json.config,
    workflowId: $workflow.id,
    executionId: $execution.id,
  };
  result = executeMorphoToBackendAdapterForN8N(input);
}


// N8N Execution - Ready to run!
return result;

if ($input.first().json.ok) {
  $('Current Info').first().json.triggerRebalancer = true;
}

return $('Current Info').first().json;

